class Solution:
    def solve(self, isConnected: List[List[int]]) -> int:
        n = len(isConnected)
        visited = set()
        res = 0
        def dfs(i):
            for j, adj in enumerate(isConnected[i]):
                if adj and j not in visited:
                    visited.add(j)
                    dfs(j)
        for i in range(n):
            if i not in visited:
                res += 1
                visited.add(i)
                dfs(i)
        return res

